use std::collections::HashMap;
use std::error::Error;

struct Record {
    id: u32,
    data: String,
}

fn process_records<T: std::fmt::Debug + From<String>>(mut records: Vec<Record>) -> Result<HashMap<u32, T>, &'static str> {
    let mut map = HashMap::new();
    for record in records {
        if record.id == 0 {
            return Err("Encountered a record with an invalid ID of zero.");
        }
        map.insert(record.id, T::from(record.data));
    }
    Ok(map)
}

fn main() -> Result<(), Box<dyn Error>> {
    let good_records = vec![ 
        Record { id: 101, data: "Valid Data A".to_string() },
        Record { id: 202, data: "Valid Data B".to_string() },
    ];

    match process_records::<String>(good_records) {
        Ok(_) => println!("Successfully processed all records."),
        Err(e) => eprintln!("Failed to process records: {}", e.to_string()),
    }

    let bad_records = vec![ 
        Record { id: 101, data: "Valid Data A".to_string() },
        Record { id: 0, data: "Junk Data".to_string() },
        Record { id: 303, data: "Valid Data C".to_string() },
    ];

    match process_records::<String>(bad_records) {
        Ok(_) => println!("Successfully processed all records."),
        Err(e) => println!("Correctly caught error on bad input: {}", e),
    }

    Ok(())
}

use std::sync::{Arc, Mutex};

struct ImageLayerAnalyzer {
    data: Arc<Mutex<Vec<u64>>>, 
}

impl ImageLayerAnalyzer {
    fn new() -> Self {
        ImageLayerAnalyzer {
            data: Arc::new(Mutex::new(Vec::new()))
        }
    }

    fn add_size(&self, size: u64) {
        let mut data = self.data.lock().unwrap();
        data.push(size);
    }

    fn calculate_total_size(&self) -> Result<u64, String> {
        let data = self.data.lock().map_err(|e| format!("Poisoned lock: {}", e));
        match data {
            Ok(guard) => Ok(guard.iter().sum()),
            Err(e) => Err(format!("Failed to acquire lock for reading: {}", e))
        }
    }
}

fn main() {
    let analyzer = ImageLayerAnalyzer::new();

    analyzer.add_size(1024);
    analyzer.add_size(512);

    let total_size = analyzer.calculate_total_size().expect("Calculation failed");
    println!("Total analyzed size: {}", total_size);
}

use std::error::Error;

trait ProcessableData {
    fn calculate_mean(self) -> Result<f64, Box<dyn Error>>;
}

struct CpuReading { cpu_usage: f64, timestamp: u64 }

impl ProcessableData for CpuReading {
    fn calculate_mean(self) -> Result<f64, Box<dyn Error>> {
        Ok(self.cpu_usage)
    }
}

struct MemoryReading { total_bytes: f64, used_bytes: f64 }

impl ProcessableData for MemoryReading {
    fn calculate_mean(self) -> Result<f64, Box<dyn Error>> {
        Ok((self.total_bytes - self.used_bytes) / self.total_bytes)
    }
}

fn monitor_and_process<T: ProcessableData>(data_source: T) -> Result<f64, Box<dyn Error>> {
    data_source.calculate_mean()
}

fn main() {
    let cpu = CpuReading { cpu_usage: 0.75, timestamp: 1678886400 };
    let mem = MemoryReading { total_bytes: 32.0, used_bytes: 10.0 };

    match monitor_and_process(cpu) {
        Ok(mean) => println!("CPU Mean Result: {}", mean),
        Err(e) => eprintln!("Error processing CPU data: {}", e),
    }

    match monitor_and_process(mem) {
        Ok(mean) => println!("Memory Ratio Result: {}", mean),
        Err(e) => eprintln!("Error processing Memory data: {}", e),
    }
}

use std::collections::BTreeMap;
use std::fmt::{self, Debug};

trait Cleanupable {
    fn cleanup(&self);
}

struct RecordA { data: String } 
impl Cleanupable for RecordA { fn cleanup(&self) { println!("Cleaning up Record A's resources."); }
}

struct RecordB { count: u32 } 
impl Cleanupable for RecordB { fn cleanup(&self) { println!("Cleaning up Record B's allocated memory block."); }
}

struct GenericRecord<T: Cleanupable> { record: T } 

impl<T: Cleanupable> Drop for GenericRecord<T> { 
    fn drop(&mut self) {
        self.record.cleanup();
    }
}

fn main() {
    let mut store: BTreeMap<&str, Box<dyn Cleanupable>> = BTreeMap::new();
    store.insert("key1", Box::new(RecordA { data: String::from("data") }));
    store.insert("key2", Box::new(RecordB { count: 42 }));

    drop(store);
}

use std::collections::HashMap;

trait Configurable {
    fn validate_schema(&self) -> bool;
    fn get_key(&self, key: &str) -> Option<String>;
}

struct ServerConfig {
    address: String,
    port: u16,
}
impl Configurable for ServerConfig {
    fn validate_schema(&self) -> bool {
        !self.address.is_empty() && self.port > 0
    }
    fn get_key(&self, key: &str) -> Option<String> {
        match key {
            "address" => Some(self.address.clone()),
            "port" => Some(self.port.to_string()),
            _ => None,
        }
    }
}

fn process_configs<T: Configurable>(configs: &[T]) -> HashMap<String, String> {
    let mut results = HashMap::new();
    for config in configs {
        if config.validate_schema() {
            if let Some(addr) = config.get_key("address") {
                results.insert(format!("server_instance_{}", addr), "Processed OK".to_string());
            }
        }
    }
    results
}

fn main() {
    let configs = vec![ 
        ServerConfig { address: "10.0.0.1".to_string(), port: 8080 }, 
        ServerConfig { address: "".to_string(), port: 9000 },
        ServerConfig { address: "127.0.0.1".to_string(), port: 22 }
    ];
    let processed = process_configs(&configs);
    println!("Successfully processed {} configuration entries.", processed.len());
}
